import Layout from "@/layout/index";

export default {
  path: "/modules",
  component: Layout,
  name: "Modules",
  meta: {
    title: "应用中心",
    icon: "tree-table",
  },
  children: [
    {
      path: "ppio",
      name: "PPIO",
      component: () => import("@/views/modules/PPIO"),
      meta: {
        title: "算网融合与感知",
        icon: "server",  // 算网融合 - 使用服务器图标
      },
    },
    {
      path: "federated-learning",
      name: "FederatedLearning",
      component: () => import("@/views/modules/FederatedLearning"),
      meta: {
        title: "泛在协同计算",
        icon: "nested",  // 协同计算 - 使用嵌套图标体现多节点协作
      },
    },
    {
      path: "computing-trade",
      name: "ComputingTrade",
      component: () => import("@/views/modules/ComputingTrade"),
      meta: {
        title: "资源编排与调度",
        icon: "monitor",  // 资源调度 - 使用监控图标
      },
    },
    {
      path: "webase",
      name: "WeBase",
      component: () => import("@/views/modules/WeBase"),
      meta: {
        title: "可信生态与溯源",
        icon: "component",  // 可信生态 - 使用组件图标体现生态特性
      },
    },
  ],
};
